import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;

/**
 * Utility class for AES encryption operations.
 * This service provides methods to encrypt data using AES algorithm.
 */
public class AESService {

    private static final String AES_ALGORITHM = "AES";
    // Using ECB mode to strictly adhere to the method signature (encrypt(key, data)).
    // Note: For production systems requiring high security, CBC or GCM with a random IV is recommended.
    private static final String TRANSFORMATION = "AES/ECB/PKCS5Padding";

    /**
     * Encrypts the given data using AES encryption.
     *
     * @param key  The encryption key string. It will be hashed to a 256-bit key.
     * @param data The plaintext data to encrypt as a byte array.
     * @return The ciphertext as a hexadecimal string.
     */
    public static String encrypt(String key, byte[] data) {
        try {
            // Create a 256-bit key from the input string using SHA-256
            byte[] keyBytes = generateKeyBytes(key);
            SecretKeySpec secretKey = new SecretKeySpec(keyBytes, AES_ALGORITHM);

            // Initialize cipher
            Cipher cipher = Cipher.getInstance(TRANSFORMATION);
            cipher.init(Cipher.ENCRYPT_MODE, secretKey);

            // Perform encryption
            byte[] encryptedBytes = cipher.doFinal(data);

            // Convert encrypted bytes to Hex string
            return bytesToHex(encryptedBytes);

        } catch (Exception e) {
            // Handle exceptions (NoSuchAlgorithmException, InvalidKeyException, etc.)
            throw new RuntimeException("Failed to encrypt data", e);
        }
    }

    /**
     * Generates a 256-bit key from the given string using SHA-256.
     *
     * @param key The input key string.
     * @return A byte array representing the 256-bit key.
     * @throws NoSuchAlgorithmException If SHA-256 is not available.
     */
    private static byte[] generateKeyBytes(String key) throws NoSuchAlgorithmException {
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        return digest.digest(key.getBytes(StandardCharsets.UTF_8));
    }

    /**
     * Converts a byte array to a hexadecimal string.
     *
     * @param bytes The byte array to convert.
     * @return The hexadecimal string representation.
     */
    private static String bytesToHex(byte[] bytes) {
        StringBuilder hexString = new StringBuilder();
        for (byte b : bytes) {
            String hex = Integer.toHexString(0xff & b);
            if (hex.length() == 1) {
                hexString.append('0');
            }
            hexString.append(hex);
        }
        return hexString.toString();
    }
}

